import { tokens } from '../../styles/tokens';

/**
 * Skeleton - Loading placeholder with pulse animation.
 *
 * Props:
 *   width     - CSS width (default: '100%')
 *   height    - CSS height (default: 16)
 *   circle    - Render as circle (overrides width/height to match)
 *   lines     - Number of text lines to render (overrides single skeleton)
 *   className - Additional CSS class
 *   style     - Additional inline styles
 */
export default function Skeleton({
  width = '100%',
  height = 16,
  circle = false,
  lines = 0,
  className,
  style,
}) {
  const baseStyle = {
    background: `linear-gradient(90deg, ${tokens.color.surfaceHover} 25%, ${tokens.color.surfaceActive} 50%, ${tokens.color.surfaceHover} 75%)`,
    backgroundSize: '200% 100%',
    animation: 'skeletonPulse 1.5s ease-in-out infinite',
    borderRadius: circle ? tokens.radius.full : tokens.radius.sm,
  };

  // Render multiple lines
  if (lines > 0) {
    return (
      <>
        <style>{skeletonKeyframes}</style>
        <div style={{ display: 'flex', flexDirection: 'column', gap: 8, ...style }} className={className}>
          {Array.from({ length: lines }, (_, i) => (
            <div
              key={i}
              style={{
                ...baseStyle,
                width: i === lines - 1 ? '60%' : '100%',
                height,
              }}
            />
          ))}
        </div>
      </>
    );
  }

  // Single skeleton
  const singleStyle = {
    ...baseStyle,
    width: circle ? height : width,
    height,
    ...style,
  };

  return (
    <>
      <style>{skeletonKeyframes}</style>
      <div style={singleStyle} className={className} />
    </>
  );
}

const skeletonKeyframes = `
@keyframes skeletonPulse {
  0% { background-position: 200% 0; }
  100% { background-position: -200% 0; }
}
`;

/**
 * SkeletonGroup - Convenience wrapper to render a common loading state.
 * Renders a card-shaped skeleton with optional title line + value line.
 */
export function SkeletonCard({ count = 1, style }) {
  return (
    <div style={{ display: 'grid', gridTemplateColumns: `repeat(${Math.min(count, 4)}, 1fr)`, gap: tokens.spacing.md, ...style }}>
      {Array.from({ length: count }, (_, i) => (
        <div
          key={i}
          style={{
            background: tokens.glass.bg,
            borderRadius: tokens.radius.lg,
            padding: tokens.spacing.lg,
            border: `1px solid ${tokens.glass.border}`,
          }}
        >
          <Skeleton width="50%" height={10} style={{ marginBottom: 8 }} />
          <Skeleton width="80%" height={20} />
        </div>
      ))}
    </div>
  );
}
